(window.webpackJsonp=window.webpackJsonp||[]).push([[968],{942:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val, left, right) {\\n *     this.val = (val===undefined ? 0 : val)\\n *     this.left = (left===undefined ? null : left)\\n *     this.right = (right===undefined ? null : right)\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> BSTIterator = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root</span>) </span>{\\n    <span class=\\"hljs-keyword\\">this</span>.stack=[]\\n    <span class=\\"hljs-keyword\\">let</span> node=root\\n    <span class=\\"hljs-keyword\\">while</span>(node){\\n        <span class=\\"hljs-keyword\\">this</span>.stack.push(node)\\n        node=node.left\\n    }\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * @return {number}\\n */</span>\\nBSTIterator.prototype.next = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-keyword\\">this</span>.stack.pop()\\n    <span class=\\"hljs-keyword\\">let</span> node=res.right\\n    <span class=\\"hljs-keyword\\">while</span>(node){\\n        <span class=\\"hljs-keyword\\">this</span>.stack.push(node)\\n        node=node.left\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res.val\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * @return {boolean}\\n */</span>\\nBSTIterator.prototype.hasNext = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-keyword\\">this</span>.stack.length&gt;<span class=\\"hljs-number\\">0</span>\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * Your BSTIterator object will be instantiated and called as such:\\n * var obj = new BSTIterator(root)\\n * var param_1 = obj.next()\\n * var param_2 = obj.hasNext()\\n */</span>\\n</code></pre>\\n"],"titleSlug":"binary-search-tree-iterator","hasThinking":false,"content":"\u5b9e\u73b0\u4e00\u4e2a\u4e8c\u53c9\u641c\u7d22\u6811\u8fed\u4ee3\u5668\u7c7b<code>BSTIterator</code> \uff0c\u8868\u793a\u4e00\u4e2a\u6309\u4e2d\u5e8f\u904d\u5386\u4e8c\u53c9\u641c\u7d22\u6811\uff08BST\uff09\u7684\u8fed\u4ee3\u5668\uff1a\\n<div class=\\"original__bRMd\\">\\n<div>\\n<ul>\\n\\t<li><code>BSTIterator(TreeNode root)</code> \u521d\u59cb\u5316 <code>BSTIterator</code> \u7c7b\u7684\u4e00\u4e2a\u5bf9\u8c61\u3002BST \u7684\u6839\u8282\u70b9 <code>root</code> \u4f1a\u4f5c\u4e3a\u6784\u9020\u51fd\u6570\u7684\u4e00\u90e8\u5206\u7ed9\u51fa\u3002\u6307\u9488\u5e94\u521d\u59cb\u5316\u4e3a\u4e00\u4e2a\u4e0d\u5b58\u5728\u4e8e BST \u4e2d\u7684\u6570\u5b57\uff0c\u4e14\u8be5\u6570\u5b57\u5c0f\u4e8e BST \u4e2d\u7684\u4efb\u4f55\u5143\u7d20\u3002</li>\\n\\t<li><code>boolean hasNext()</code> \u5982\u679c\u5411\u6307\u9488\u53f3\u4fa7\u904d\u5386\u5b58\u5728\u6570\u5b57\uff0c\u5219\u8fd4\u56de <code>true</code> \uff1b\u5426\u5219\u8fd4\u56de <code>false</code> \u3002</li>\\n\\t<li><code>int next()</code>\u5c06\u6307\u9488\u5411\u53f3\u79fb\u52a8\uff0c\u7136\u540e\u8fd4\u56de\u6307\u9488\u5904\u7684\u6570\u5b57\u3002</li>\\n</ul>\\n\\n<p>\u6ce8\u610f\uff0c\u6307\u9488\u521d\u59cb\u5316\u4e3a\u4e00\u4e2a\u4e0d\u5b58\u5728\u4e8e BST \u4e2d\u7684\u6570\u5b57\uff0c\u6240\u4ee5\u5bf9 <code>next()</code> \u7684\u9996\u6b21\u8c03\u7528\u5c06\u8fd4\u56de BST \u4e2d\u7684\u6700\u5c0f\u5143\u7d20\u3002</p>\\n</div>\\n</div>\\n\\n<p>\u4f60\u53ef\u4ee5\u5047\u8bbe\xa0<code>next()</code>\xa0\u8c03\u7528\u603b\u662f\u6709\u6548\u7684\uff0c\u4e5f\u5c31\u662f\u8bf4\uff0c\u5f53\u8c03\u7528 <code>next()</code>\xa0\u65f6\uff0cBST \u7684\u4e2d\u5e8f\u904d\u5386\u4e2d\u81f3\u5c11\u5b58\u5728\u4e00\u4e2a\u4e0b\u4e00\u4e2a\u6570\u5b57\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2018/12/25/bst-tree.png\\" style=\\"width: 189px; height: 178px;\\" />\\n<pre>\\n<strong>\u8f93\u5165</strong>\\n[\\"BSTIterator\\", \\"next\\", \\"next\\", \\"hasNext\\", \\"next\\", \\"hasNext\\", \\"next\\", \\"hasNext\\", \\"next\\", \\"hasNext\\"]\\n[[[7, 3, 15, null, null, 9, 20]], [], [], [], [], [], [], [], [], []]\\n<strong>\u8f93\u51fa</strong>\\n[null, 3, 7, true, 9, true, 15, true, 20, false]\\n\\n<strong>\u89e3\u91ca</strong>\\nBSTIterator bSTIterator = new BSTIterator([7, 3, 15, null, null, 9, 20]);\\nbSTIterator.next();    // \u8fd4\u56de 3\\nbSTIterator.next();    // \u8fd4\u56de 7\\nbSTIterator.hasNext(); // \u8fd4\u56de True\\nbSTIterator.next();    // \u8fd4\u56de 9\\nbSTIterator.hasNext(); // \u8fd4\u56de True\\nbSTIterator.next();    // \u8fd4\u56de 15\\nbSTIterator.hasNext(); // \u8fd4\u56de True\\nbSTIterator.next();    // \u8fd4\u56de 20\\nbSTIterator.hasNext(); // \u8fd4\u56de False\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u6811\u4e2d\u8282\u70b9\u7684\u6570\u76ee\u5728\u8303\u56f4 <code>[1, 10<sup>5</sup>]</code> \u5185</li>\\n\\t<li><code>0 <= Node.val <= 10<sup>6</sup></code></li>\\n\\t<li>\u6700\u591a\u8c03\u7528 <code>10<sup>5</sup></code> \u6b21 <code>hasNext</code> \u548c <code>next</code> \u64cd\u4f5c</li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u8fdb\u9636\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u4f60\u53ef\u4ee5\u8bbe\u8ba1\u4e00\u4e2a\u6ee1\u8db3\u4e0b\u8ff0\u6761\u4ef6\u7684\u89e3\u51b3\u65b9\u6848\u5417\uff1f<code>next()</code> \u548c <code>hasNext()</code> \u64cd\u4f5c\u5747\u644a\u65f6\u95f4\u590d\u6742\u5ea6\u4e3a <code>O(1)</code> \uff0c\u5e76\u4f7f\u7528 <code>O(h)</code> \u5185\u5b58\u3002\u5176\u4e2d <code>h</code> \u662f\u6811\u7684\u9ad8\u5ea6\u3002</li>\\n</ul>\\n","title":"173. \u4e8c\u53c9\u641c\u7d22\u6811\u8fed\u4ee3\u5668","relatedTags":["\u6808","\u6811","\u8bbe\u8ba1"],"difficult":"Middle","lang":["javascript"],"uniqueID":"173"}')}}]);